    inputSchema: {"type":"object","properties":{"name":{"type":"string","minLength":1,"maxLength":80,"default":"Jules trigger","description":"Human-readable connector label."},"events":{"type":"array","default":[],"items":{"type":"string","enum":["bug.created","feature_request.created"],"description":"Lifecycle event a connector subscribes to. `bug.created` fires when a new bug report lands in the feedback inbox; `feature_request.created` fires for a new feature request. A connector dispatches (posts to Slack / appends a Sheets row / files a GitHub Issue) — or, for trigger connectors, auto-fires a coding-agent run — once per subscribed event."},"description":"Events that auto-fire a Jules session. Defaults to empty."},"config":{"type":"object","properties":{"source":{"type":"string","minLength":1,"description":"Jules source for the connected repo, e.g. `sources/github/owner/repo`. Idempotency key for the connector."},"startingBranch":{"type":"string","minLength":1,"description":"Optional branch the session starts from."},"projectId":{"type":"string","minLength":1,"description":"Shipeasy project id the run targets."}},"required":["source","projectId"],"additionalProperties":false,"description":"Non-secret config for a Jules trigger."},"apiKey":{"type":"string","minLength":1,"description":"Jules API key that launches the session (secret). Encrypted into the credentials cipher; never returned."},"opsKey":{"type":"string","minLength":1,"description":"Restricted Shipeasy ops key, embedded in the prompt (Jules exposes no env channel) (secret). Encrypted; never returned."},"enabled":{"type":"boolean","default":true,"description":"Whether the trigger is active on create."}},"required":["config","apiKey","opsKey"]},
