    description: "Create a dynamic config. Creates a new config with the given `schema`. The initial `value` (or an empty object) is published as version 1 on **every** env.",
    inputSchema: {"type":"object","properties":{"name":{"type":"string","maxLength":128,"pattern":"^(?:_default|[a-z0-9](?:[a-z0-9_-]*[a-z0-9])?)\\.[a-z0-9](?:[a-z0-9_-]*[a-z0-9])?$","description":"Stable config/killswitch key in `folder.name` form (two lowercase segments separated by a dot, e.g. `pricing.tiers`). Immutable after create."},"description":{"description":"Optional free-form description shown in the dashboard. Max 512 chars.","type":"string","maxLength":512},"folder":{"anyOf":[{"type":"string","maxLength":256,"pattern":"^[a-zA-Z0-9_-]+$"},{"type":"null"}],"description":"Optional folder name grouping items in the dashboard. Alphanumeric, `_` or `-` (no `/`). Part of the SDK lookup key (`<folder>/<name>`)."},"schema":{"type":"object","additionalProperties":{},"description":"JSON Schema (draft 2020-12) describing the shape of the config value. Top-level `type` must be `'object'`; every published value is validated against this schema."},"value":{"description":"Initial config value. Either a single JSON object applied to every env, or a `{ env: value }` map seeding per-env values. Must match `schema`. Defaults to `{}` on every env when omitted."}},"required":["name","schema"]},
